// Image Optimizer - Adaptive image loading based on network
window.ImageOptimizer={_networkType:"4g",_quality:.75,_supportWebP:!1,init:function(){this._detectWebPSupport(),this._detectNetwork(),this._setupNetworkListener(),this._optimizeImages(),console.log("[ImageOptimizer] ✅ Initialized")},_detectWebPSupport:function(){const e=document.createElement("canvas");e.width=1,e.height=1;try{this._supportWebP="image/webp"===e.toDataURL("image/webp")}catch(e){this._supportWebP=!1}},_detectNetwork:function(){if(!navigator.connection)return;const e=navigator.connection.effectiveType;this._networkType=e,this._adjustQualityByNetwork(e)},_setupNetworkListener:function(){navigator.connection&&navigator.connection.addEventListener("change",()=>{this._detectNetwork(),this._optimizeImages()})},_adjustQualityByNetwork:function(e){switch(e){case"4g":this._quality=.9;break;case"3g":this._quality=.7;break;case"2g":this._quality=.5;break;default:this._quality=.75}console.log(`[ImageOptimizer] Network: ${e}, Quality: ${this._quality}`)},_optimizeImages:function(){const e=document.querySelectorAll("img[data-src]");e.forEach(e=>{const t=e.getAttribute("data-src");if(!t)return;const i=this._getOptimizedSrc(t);e.src=i,e.removeAttribute("data-src")})},_getOptimizedSrc:function(e){if(!e)return"";if(e.includes("icon-512.png")){const t=Math.round(512*this._quality);return`${e}?w=${t}&q=${Math.round(100*this._quality)}`}return e},preloadImage:function(e){const t=new Image;t.src=this._getOptimizedSrc(e)},getStats:function(){return{networkType:this._networkType,quality:this._quality,supportWebP:this._supportWebP}}};document.addEventListener("DOMContentLoaded",()=>{window.ImageOptimizer.init()});
